 {"id":"bd-1sp","title":"Implement Common Table Expressions (CTEs)","description":"## Description

Support WITH clauses for Common Table Expressions.

## Python Behavior

```python
from sqlalchemy import select, cte

# Basic CTE
active_users = select(User).where(User.active == True).cte('active_users')

stmt = select(active_users.c.name).select_from(active_users)

# Recursive CTE
hierarchy = select(Employee).where(Employee.manager_id == None).cte('hierarchy', recursive=True)

subordinates = select(Employee).join(
    hierarchy, Employee.manager_id == hierarchy.c.id
)

hierarchy = hierarchy.union(subordinates)

stmt = select(hierarchy)
```

## Rust Implementation

```rust
// Basic CTE
let active_users = select!(User)
    .filter(User::active.eq(true))
    .cte("active_users");

let query = select_from(&active_users)
    .columns(["name"]);

// Recursive CTE
let hierarchy = select!(Employee)
    .filter(Employee::manager_id.is_null())
    .cte_recursive("hierarchy");

let subordinates = select!(Employee)
    .join_cte(&hierarchy, Employee::manager_id.eq(hierarchy.col("id")));

let query = hierarchy.union(subordinates);
```

### SQL Output

```sql
WITH RECURSIVE hierarchy AS (
    SELECT * FROM employees WHERE manager_id IS NULL
    UNION
    SELECT e.* FROM employees e 
    JOIN hierarchy h ON e.manager_id = h.id
)
SELECT * FROM hierarchy
```

